  1→package cli
  2→
  3→import (
  4→	"bufio"
  5→	"encoding/json"
  6→	"fmt"
  7→	"io"
  8→	"os"
  9→	"path/filepath"
 10→	"strings"
 11→
 12→	"github.com/entireio/cli/cmd/entire/cli/agent/claudecode"
 13→	"github.com/entireio/cli/cmd/entire/cli/textutil"
 14→	"github.com/entireio/cli/cmd/entire/cli/transcript"
 15→)
 16→
 17→// Transcript message type constants - aliases to transcript package for local use.
 18→const (
 19→	transcriptTypeUser      = transcript.TypeUser
 20→	transcriptTypeAssistant = transcript.TypeAssistant
 21→	contentTypeText         = transcript.ContentTypeText
 22→	contentTypeToolUse      = transcript.ContentTypeToolUse
 23→)
 24→
 25→// parseTranscript reads and parses a Claude Code transcript file.
 26→// Uses bufio.Reader to handle arbitrarily long lines.
 27→func parseTranscript(path string) ([]transcriptLine, error) {
 28→	file, err := os.Open(path) //nolint:gosec // Reading from controlled git metadata path
 29→	if err != nil {
 30→		return nil, err //nolint:wrapcheck // already present in codebase
 31→	}
 32→	defer func() { _ = file.Close() }()
 33→
 34→	var lines []transcriptLine
 35→	reader := bufio.NewReader(file)
 36→
 37→	for {
 38→		lineBytes, err := reader.ReadBytes('\n')
 39→		if err != nil && err != io.EOF {
 40→			return nil, fmt.Errorf("failed to read transcript: %w", err)
 41→		}
 42→
 43→		// Handle empty line or EOF without content
 44→		if len(lineBytes) == 0 {
 45→			if err == io.EOF {
 46→				break
 47→			}
 48→			continue
 49→		}
 50→
 51→		var line transcriptLine
 52→		if err := json.Unmarshal(lineBytes, &line); err == nil {
 53→			lines = append(lines, line)
 54→		}
 55→
 56→		if err == io.EOF {
 57→			break
 58→		}
 59→	}
 60→
 61→	return lines, nil
 62→}
 63→
 64→// parseTranscriptFromLine reads and parses a transcript file starting from a specific line.
 65→// Uses bufio.Reader to handle arbitrarily long lines.
 66→// Returns:
 67→//   - lines: parsed transcript lines from startLine onwards (malformed lines skipped)
 68→//   - totalLines: total number of lines in the file (including malformed ones)
 69→//   - error: any error encountered during reading
 70→//
 71→// The startLine parameter is 0-indexed (startLine=0 reads from the beginning).
 72→// This is useful for incremental parsing when you've already processed some lines.
 73→func parseTranscriptFromLine(path string, startLine int) ([]transcriptLine, int, error) {
 74→	file, err := os.Open(path) //nolint:gosec // path is a controlled transcript file path
 75→	if err != nil {
 76→		return nil, 0, fmt.Errorf("failed to open transcript: %w", err)
 77→	}
 78→	defer func() { _ = file.Close() }()
 79→
 80→	var lines []transcriptLine
 81→	reader := bufio.NewReader(file)
 82→
 83→	totalLines := 0
 84→	for {
 85→		lineBytes, err := reader.ReadBytes('\n')
 86→		if err != nil && err != io.EOF {
 87→			return nil, 0, fmt.Errorf("failed to read transcript: %w", err)
 88→		}
 89→
 90→		// Handle empty line or EOF without content
 91→		if len(lineBytes) == 0 {
 92→			if err == io.EOF {
 93→				break
 94→			}
 95→			continue
 96→		}
 97→
 98→		// Count all lines for totalLines, but only parse after startLine
 99→		if totalLines >= startLine {
100→			var line transcriptLine
101→			if err := json.Unmarshal(lineBytes, &line); err == nil {
102→				lines = append(lines, line)
103→			}
104→		}
105→		totalLines++
106→
107→		if err == io.EOF {
108→			break
109→		}
110→	}
111→
112→	return lines, totalLines, nil
113→}
114→
115→// parseTranscriptFromBytes parses transcript content from a byte slice.
116→// Uses bufio.Reader to handle arbitrarily long lines.
117→func parseTranscriptFromBytes(content []byte) ([]transcriptLine, error) {
118→	lines, err := transcript.ParseFromBytes(content)
119→	if err != nil {
120→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
121→	}
122→	return lines, nil
123→}
124→
125→// PromptResponsePair represents a user prompt and the assistant's responses.
126→// Used for extracting all interactions from a transcript.
127→type PromptResponsePair struct {
128→	Prompt    string
129→	Responses []string // Multiple responses can occur between tool calls
130→	Files     []string
131→}
132→
133→// ExtractAllPromptResponses extracts all user prompt and assistant response pairs from a transcript.
134→// Returns pairs in chronological order (oldest first).
135→// Each pair contains the user's prompt, assistant's text response, and files modified.
136→func ExtractAllPromptResponses(transcript []transcriptLine) []PromptResponsePair {
137→	var pairs []PromptResponsePair
138→
139→	// Find all user prompts (messages with string content, not tool results)
140→	var userIndices []int
141→	for i, line := range transcript {
142→		if line.Type == transcriptTypeUser {
143→			var msg userMessage
144→			if err := json.Unmarshal(line.Message, &msg); err != nil {
145→				continue
146→			}
147→			// Only count messages with string content (real user prompts)
148→			if _, ok := msg.Content.(string); ok {
149→				userIndices = append(userIndices, i)
150→			} else if arr, ok := msg.Content.([]interface{}); ok {
151→				// Check if array has text blocks (also a real user prompt)
152→				for _, item := range arr {
153→					if m, ok := item.(map[string]interface{}); ok {
154→						if m["type"] == contentTypeText {
155→							userIndices = append(userIndices, i)
156→							break
157→						}
158→					}
159→				}
160→			}
161→		}
162→	}
163→
164→	// For each user prompt, extract the prompt text, following assistant response, and files
165→	for idx, userIdx := range userIndices {
166→		// Determine the range for this prompt's conversation
167→		endIdx := len(transcript)
168→		if idx < len(userIndices)-1 {
169→			endIdx = userIndices[idx+1]
170→		}
171→
172→		// Extract prompt text
173→		prompt := extractUserPromptAt(transcript, userIdx)
174→		if prompt == "" {
175→			continue
176→		}
177→
178→		// Extract assistant responses and files from this range
179→		slice := transcript[userIdx:endIdx]
180→		responses := extractAssistantResponses(slice)
181→		files := extractModifiedFiles(slice)
182→
183→		pairs = append(pairs, PromptResponsePair{
184→			Prompt:    prompt,
185→			Responses: responses,
186→			Files:     files,
187→		})
188→	}
189→
190→	return pairs
191→}
192→
193→// extractUserPromptAt extracts the user prompt at the given index.
194→// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
195→func extractUserPromptAt(lines []transcriptLine, idx int) string {
196→	if idx >= len(lines) || lines[idx].Type != transcriptTypeUser {
197→		return ""
198→	}
199→
200→	return transcript.ExtractUserContent(lines[idx].Message)
201→}
202→
203→// extractAssistantResponses collects all assistant text blocks from the given transcript slice.
204→// A single prompt can trigger multiple assistant responses interspersed with tool calls.
205→func extractAssistantResponses(transcript []transcriptLine) []string {
206→	var texts []string
207→	for _, line := range transcript {
208→		if line.Type == transcriptTypeAssistant {
209→			var msg assistantMessage
210→			if err := json.Unmarshal(line.Message, &msg); err != nil {
211→				continue
212→			}
213→
214→			for _, block := range msg.Content {
215→				if block.Type == contentTypeText && block.Text != "" {
216→					texts = append(texts, block.Text)
217→				}
218→			}
219→		}
220→	}
221→	return texts
222→}
223→
224→// extractUserPrompts extracts all user messages from the transcript in order.
225→// Only considers messages with string content (not tool results).
226→// IDE-injected context tags (like <ide_opened_file>) are stripped from the results.
227→func extractUserPrompts(transcript []transcriptLine) []string {
228→	var prompts []string
229→	for i := range transcript {
230→		if transcript[i].Type != transcriptTypeUser {
231→			continue
232→		}
233→		var msg userMessage
234→		if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
235→			continue
236→		}
237→
238→		// Handle string content
239→		if str, ok := msg.Content.(string); ok {
240→			prompts = append(prompts, textutil.StripIDEContextTags(str))
241→			continue
242→		}
243→
244→		// Handle array content (only if it contains text blocks)
245→		if arr, ok := msg.Content.([]interface{}); ok {
246→			var texts []string
247→			for _, item := range arr {
248→				if m, ok := item.(map[string]interface{}); ok {
249→					if m["type"] == contentTypeText {
250→						if text, ok := m["text"].(string); ok {
251→							texts = append(texts, text)
252→						}
253→					}
254→				}
255→			}
256→			if len(texts) > 0 {
257→				prompts = append(prompts, textutil.StripIDEContextTags(strings.Join(texts, "\n\n")))
258→			}
259→		}
260→	}
261→	return prompts
262→}
263→
264→// extractLastUserPrompt extracts the last user message from the transcript.
265→// Only considers messages with string content (not tool results).
266→// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
267→func extractLastUserPrompt(transcript []transcriptLine) string {
268→	prompts := extractUserPrompts(transcript)
269→	if len(prompts) == 0 {
270→		return ""
271→	}
272→	return prompts[len(prompts)-1]
273→}
274→
275→// extractLastAssistantMessage extracts the last text message from the assistant
276→func extractLastAssistantMessage(transcript []transcriptLine) string {
277→	for i := len(transcript) - 1; i >= 0; i-- {
278→		if transcript[i].Type == transcriptTypeAssistant {
279→			var msg assistantMessage
280→			if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
281→				continue
282→			}
283→
284→			for _, block := range msg.Content {
285→				if block.Type == contentTypeText && block.Text != "" {
286→					return block.Text
287→				}
288→			}
289→		}
290→	}
291→	return ""
292→}
293→
294→// findLastUserUUID finds the UUID of the last user message (that has string content)
295→func findLastUserUUID(transcript []transcriptLine) string {
296→	for i := len(transcript) - 1; i >= 0; i-- {
297→		if transcript[i].Type == transcriptTypeUser {
298→			var msg userMessage
299→			if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
300→				continue
301→			}
302→			// Only count messages with string content (not tool results)
303→			if _, ok := msg.Content.(string); ok {
304→				return transcript[i].UUID
305→			}
306→		}
307→	}
308→	return ""
309→}
310→
311→// filterTranscriptAfterUUID returns transcript lines after the given UUID
312→func filterTranscriptAfterUUID(transcript []transcriptLine, uuid string) []transcriptLine {
313→	if uuid == "" {
314→		return transcript
315→	}
316→
317→	foundIndex := -1
318→	for i, line := range transcript {
319→		if line.UUID == uuid {
320→			foundIndex = i
321→			break
322→		}
323→	}
324→
325→	if foundIndex == -1 || foundIndex == len(transcript)-1 {
326→		return transcript
327→	}
328→
329→	return transcript[foundIndex+1:]
330→}
331→
332→// extractModifiedFiles extracts the list of files modified by tool calls
333→func extractModifiedFiles(transcript []transcriptLine) []string {
334→	fileSet := make(map[string]bool)
335→	var files []string
336→
337→	for _, line := range transcript {
338→		if line.Type == transcriptTypeAssistant {
339→			var msg assistantMessage
340→			if err := json.Unmarshal(line.Message, &msg); err != nil {
341→				continue
342→			}
343→
344→			for _, block := range msg.Content {
345→				if block.Type == contentTypeToolUse {
346→					isModifyTool := false
347→					for _, name := range claudecode.FileModificationTools {
348→						if block.Name == name {
349→							isModifyTool = true
350→							break
351→						}
352→					}
353→
354→					if isModifyTool {
355→						var input toolInput
356→						if err := json.Unmarshal(block.Input, &input); err != nil {
357→							continue
358→						}
359→
360→						file := input.FilePath
361→						if file == "" {
362→							file = input.NotebookPath
363→						}
364→
365→						if file != "" && !fileSet[file] {
366→							fileSet[file] = true
367→							files = append(files, file)
368→						}
369→					}
370→				}
371→			}
372→		}
373→	}
374→
375→	return files
376→}
377→
378→// extractKeyActions extracts key actions from the transcript for context file
379→func extractKeyActions(transcript []transcriptLine, maxActions int) []string {
380→	var keyActions []string
381→
382→	for _, line := range transcript {
383→		if line.Type == transcriptTypeAssistant {
384→			var msg assistantMessage
385→			if err := json.Unmarshal(line.Message, &msg); err != nil {
386→				continue
387→			}
388→
389→			for _, block := range msg.Content {
390→				if block.Type == contentTypeToolUse {
391→					var input toolInput
392→					_ = json.Unmarshal(block.Input, &input) //nolint:errcheck // Best-effort parsing for display purposes
393→
394→					detail := input.Description
395→					if detail == "" {
396→						detail = input.Command
397→					}
398→					if detail == "" {
399→						detail = input.FilePath
400→					}
401→					if detail == "" {
402→						detail = input.Pattern
403→					}
404→
405→					action := "- **" + block.Name + "**: " + detail
406→					keyActions = append(keyActions, action)
407→					if len(keyActions) >= maxActions {
408→						return keyActions
409→					}
410→				}
411→			}
412→		}
413→	}
414→
415→	return keyActions
416→}
417→
418→// AgentTranscriptPath returns the path to a subagent's transcript file.
419→// Subagent transcripts are stored as agent-{agentId}.jsonl in the same directory
420→// as the main transcript.
421→func AgentTranscriptPath(transcriptDir, agentID string) string {
422→	return filepath.Join(transcriptDir, fmt.Sprintf("agent-%s.jsonl", agentID))
423→}
424→
425→// toolResultBlock represents a tool_result in a user message
426→type toolResultBlock struct {
427→	Type      string `json:"type"`
428→	ToolUseID string `json:"tool_use_id"`
429→}
430→
431→// userMessageWithToolResults represents a user message that may contain tool results
432→type userMessageWithToolResults struct {
433→	Content []toolResultBlock `json:"content"`
434→}
435→
436→// FindCheckpointUUID finds the UUID of the message containing the tool_result
437→// for the given tool_use_id. This is used to find the checkpoint point for
438→// transcript truncation when rewinding to a task.
439→// Returns the UUID and true if found, empty string and false otherwise.
440→func FindCheckpointUUID(transcript []transcriptLine, toolUseID string) (string, bool) {
441→	for _, line := range transcript {
442→		if line.Type != transcriptTypeUser {
443→			continue
444→		}
445→
446→		var msg userMessageWithToolResults
447→		if err := json.Unmarshal(line.Message, &msg); err != nil {
448→			continue
449→		}
450→
451→		for _, block := range msg.Content {
452→			if block.Type == "tool_result" && block.ToolUseID == toolUseID {
453→				return line.UUID, true
454→			}
455→		}
456→	}
457→	return "", false
458→}
459→
460→// TruncateTranscriptAtUUID returns transcript lines up to and including the
461→// line with the given UUID. If the UUID is not found or is empty, returns
462→// the entire transcript.
463→//
464→//nolint:revive // Exported for testing purposes
465→func TruncateTranscriptAtUUID(transcript []transcriptLine, uuid string) []transcriptLine {
466→	if uuid == "" {
467→		return transcript
468→	}
469→
470→	for i, line := range transcript {
471→		if line.UUID == uuid {
472→			return transcript[:i+1]
473→		}
474→	}
475→
476→	// UUID not found, return full transcript
477→	return transcript
478→}
479→
480→// writeTranscript writes transcript lines to a file in JSONL format.
481→func writeTranscript(path string, transcript []transcriptLine) error {
482→	file, err := os.Create(path) //nolint:gosec // Writing to controlled git metadata path
483→	if err != nil {
484→		return fmt.Errorf("failed to create file: %w", err)
485→	}
486→	defer func() { _ = file.Close() }()
487→
488→	for _, line := range transcript {
489→		data, err := json.Marshal(line)
490→		if err != nil {
491→			return fmt.Errorf("failed to marshal line: %w", err)
492→		}
493→		if _, err := file.Write(data); err != nil {
