281→// getFileChanges returns the current file changes from git status.
282→// Returns (modifiedFiles, untrackedFiles, deletedFiles, stagedFiles, error)
283→func getFileChanges() ([]string, []string, []string, []string, error) {
284→	repo, err := openRepository()
285→	if err != nil {
286→		return nil, nil, nil, nil, err
287→	}
288→
289→	worktree, err := repo.Worktree()
290→	if err != nil {
291→		return nil, nil, nil, nil, fmt.Errorf("getting worktree: %w", err)
292→	}
293→
294→	status, err := worktree.Status()
295→	if err != nil {
296→		return nil, nil, nil, nil, fmt.Errorf("getting status: %w", err)
297→	}
298→
299→	var modifiedFiles, untrackedFiles, deletedFiles, stagedFiles []string
300→
301→	for file, st := range status {
302→		// Skip .entire directory
303→		if paths.IsInfrastructurePath(file) {
304→			continue
305→		}
306→
307→		// Check staging area first
308→		switch st.Staging {
309→		case git.Added, git.Modified:
310→			stagedFiles = append(stagedFiles, file)
311→			continue
312→		case git.Deleted:
313→			deletedFiles = append(deletedFiles, file)
314→			continue
315→		case git.Unmodified, git.Renamed, git.Copied, git.UpdatedButUnmerged, git.Untracked:
316→			// Fall through to check worktree status
317→		}
318→
319→		// Check worktree status
320→		switch st.Worktree {
321→		case git.Modified:
322→			modifiedFiles = append(modifiedFiles, file)
323→		case git.Untracked:
324→			untrackedFiles = append(untrackedFiles, file)
325→		case git.Deleted:
326→			deletedFiles = append(deletedFiles, file)
327→		case git.Unmodified, git.Added, git.Renamed, git.Copied, git.UpdatedButUnmerged:
328→			// No action needed
329→		}
330→	}
331→
332→	// Sort for consistent output
333→	sort.Strings(modifiedFiles)
334→	sort.Strings(untrackedFiles)
335→	sort.Strings(deletedFiles)
336→	sort.Strings(stagedFiles)
337→
338→	return modifiedFiles, untrackedFiles, deletedFiles, stagedFiles, nil
339→}
340→
341→// findTranscriptForSession attempts to find the transcript file for a session.
342→// Returns the path if found, empty string if not found, or error on failure.
343→func findTranscriptForSession(sessionID string) (string, error) {
344→	// Try to get agent type from session state
345→	sessionState, err := strategy.LoadSessionState(sessionID)
346→	if err != nil {
347→		return "", fmt.Errorf("failed to load session state: %w", err)
348→	}
349→
350→	var ag agent.Agent
351→	if sessionState != nil && sessionState.AgentType != "" {
352→		ag, err = agent.GetByAgentType(sessionState.AgentType)
353→		if err != nil {
354→			return "", fmt.Errorf("failed to get agent for type %q: %w", sessionState.AgentType, err)
355→		}
356→	} else {
357→		return "", fmt.Errorf("failed to get agent from sessionID: %s", sessionID)
358→	}
359→
360→	// Resolve transcript path (checks session state's transcript_path first,
361→	// falls back to agent's GetSessionDir + ResolveSessionFile)
362→	transcriptPath, err := resolveTranscriptPath(sessionID, ag)
363→	if err != nil {
364→		return "", fmt.Errorf("failed to resolve transcript path: %w", err)
365→	}
366→
367→	// Check if it exists
368→	if _, err := os.Stat(transcriptPath); err != nil {
369→		if os.IsNotExist(err) {
370→			return "", nil // Not found, but not an error
371→		}
372→		return "", fmt.Errorf("failed to stat transcript: %w", err)
373→	}
374→
375→	return transcriptPath, nil
376→}
