204→// contains a usage object with input_tokens, output_tokens, and cache tokens.
205→//
206→// Due to streaming, multiple transcript rows may share the same message.id.
207→// We deduplicate by taking the row with the highest output_tokens for each message.id.
208→func CalculateTokenUsage(transcript []TranscriptLine) *agent.TokenUsage {
209→	// Map from message.id to the usage with highest output_tokens
210→	usageByMessageID := make(map[string]messageUsage)
