547→// TestCalculateTotalTokenUsage_PerCheckpoint verifies token usage
548→// is calculated per-checkpoint, not from the full conversation.
549→// This tests the core CalculateTotalTokenUsage function which should:
550→// - From line 0: count all turns
551→// - From line N: count only turns from line N onwards
552→func TestCalculateTotalTokenUsage_PerCheckpoint(t *testing.T) {
553→	t.Parallel()
554→
555→	tmpDir := t.TempDir()
556→	transcriptPath := tmpDir + "/transcript.jsonl"
557→
558→	// Build transcript with 3 turns:
559→	// Turn 1: user + assistant (100 input, 50 output)
560→	// Turn 2: user + assistant (200 input, 100 output)
561→	// Turn 3: user + assistant (300 input, 150 output)
562→	//
563→	// Lines:
564→	// 0: user message 1
565→	// 1: assistant response 1 (100/50 tokens)
566→	// 2: user message 2
567→	// 3: assistant response 2 (200/100 tokens)
568→	// 4: user message 3
569→	// 5: assistant response 3 (300/150 tokens)
570→
571→	transcriptContent := []byte(
572→		`{"type":"user","uuid":"u1","message":{"content":"first prompt"}}` + "\n" +
573→			`{"type":"assistant","uuid":"a1","message":{"id":"m1","usage":{"input_tokens":100,"output_tokens":50}}}` + "\n" +
574→			`{"type":"user","uuid":"u2","message":{"content":"second prompt"}}` + "\n" +
575→			`{"type":"assistant","uuid":"a2","message":{"id":"m2","usage":{"input_tokens":200,"output_tokens":100}}}` + "\n" +
576→			`{"type":"user","uuid":"u3","message":{"content":"third prompt"}}` + "\n" +
577→			`{"type":"assistant","uuid":"a3","message":{"id":"m3","usage":{"input_tokens":300,"output_tokens":150}}}` + "\n",
578→	)
579→	if err := os.WriteFile(transcriptPath, transcriptContent, 0o600); err != nil {
580→		t.Fatalf("failed to write transcript: %v", err)
581→	}
582→
583→	// Test 1: From line 0 - all 3 turns = 600 input, 300 output
584→	usage1, err := CalculateTotalTokenUsage(transcriptPath, 0, "")
585→	if err != nil {
586→		t.Fatalf("CalculateTotalTokenUsage(0) error: %v", err)
587→	}
588→	if usage1.InputTokens != 600 || usage1.OutputTokens != 300 {
589→		t.Errorf("From line 0: got input=%d output=%d, want input=600 output=300",
590→			usage1.InputTokens, usage1.OutputTokens)
591→	}
592→	if usage1.APICallCount != 3 {
593→		t.Errorf("From line 0: got APICallCount=%d, want 3", usage1.APICallCount)
594→	}
595→
596→	// Test 2: From line 2 (after turn 1) - turns 2+3 only = 500 input, 250 output
597→	usage2, err := CalculateTotalTokenUsage(transcriptPath, 2, "")
598→	if err != nil {
599→		t.Fatalf("CalculateTotalTokenUsage(2) error: %v", err)
600→	}
601→	if usage2.InputTokens != 500 || usage2.OutputTokens != 250 {
602→		t.Errorf("From line 2: got input=%d output=%d, want input=500 output=250",
603→			usage2.InputTokens, usage2.OutputTokens)
604→	}
605→	if usage2.APICallCount != 2 {
606→		t.Errorf("From line 2: got APICallCount=%d, want 2", usage2.APICallCount)
607→	}
608→
609→	// Test 3: From line 4 (after turns 1+2) - turn 3 only = 300 input, 150 output
610→	usage3, err := CalculateTotalTokenUsage(transcriptPath, 4, "")
611→	if err != nil {
612→		t.Fatalf("CalculateTotalTokenUsage(4) error: %v", err)
613→	}
614→	if usage3.InputTokens != 300 || usage3.OutputTokens != 150 {
615→		t.Errorf("From line 4: got input=%d output=%d, want input=300 output=150",
616→			usage3.InputTokens, usage3.OutputTokens)
617→	}
618→	if usage3.APICallCount != 1 {
619→		t.Errorf("From line 4: got APICallCount=%d, want 1", usage3.APICallCount)
620→	}
621→}
