		{Type: "assistant", UUID: "a1", Message: []byte(`{"content":[{"type":"text","text":"Response 1"}]}`)},
		{Type: "user", UUID: "u2", Message: []byte(`{"content":"Second prompt"}`)},
		{Type: "assistant", UUID: "a2", Message: []byte(`{"content":[{"type":"text","text":"Response 2"}]}`)},
	}

