			name:      "find second task result",
			toolUseID: "toolu_task2",
			wantUUID:  "u3",
			wantFound: true,
		},
		{
			name:      "non-existent tool use ID",
			toolUseID: "toolu_nonexistent",
			wantUUID:  "",
			wantFound: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
