 25→// PromptResponsePair represents a user prompt and the assistant's responses.
 26→// Used for extracting all interactions from a transcript.
 27→type PromptResponsePair struct {
 28→	Prompt    string
 29→	Responses []string // Multiple responses can occur between tool calls
 30→	Files     []string
 31→}
