 33→// ExtractAllPromptResponses extracts all user prompt and assistant response pairs from a transcript.
 34→// Returns pairs in chronological order (oldest first).
 35→// Each pair contains the user's prompt, assistant's text response, and files modified.
 36→func ExtractAllPromptResponses(transcript []transcriptLine) []PromptResponsePair {
 37→	var pairs []PromptResponsePair
 38→
 39→	// Find all user prompts (messages with string content, not tool results)
 40→	var userIndices []int
 41→	for i, line := range transcript {
 42→		if line.Type == transcriptTypeUser {
 43→			var msg userMessage
 44→			if err := json.Unmarshal(line.Message, &msg); err != nil {
 45→				continue
 46→			}
 47→			// Only count messages with string content (real user prompts)
 48→			if _, ok := msg.Content.(string); ok {
 49→				userIndices = append(userIndices, i)
 50→			} else if arr, ok := msg.Content.([]interface{}); ok {
 51→				// Check if array has text blocks (also a real user prompt)
 52→				for _, item := range arr {
 53→					if m, ok := item.(map[string]interface{}); ok {
 54→						if m["type"] == contentTypeText {
 55→							userIndices = append(userIndices, i)
 56→							break
 57→						}
 58→					}
 59→				}
 60→			}
 61→		}
 62→	}
 63→
 64→	// For each user prompt, extract the prompt text, following assistant response, and files
 65→	for idx, userIdx := range userIndices {
 66→		// Determine the range for this prompt's conversation
 67→		endIdx := len(transcript)
 68→		if idx < len(userIndices)-1 {
 69→			endIdx = userIndices[idx+1]
 70→		}
 71→
 72→		// Extract prompt text
 73→		prompt := extractUserPromptAt(transcript, userIdx)
 74→		if prompt == "" {
 75→			continue
 76→		}
 77→
 78→		// Extract assistant responses and files from this range
 79→		slice := transcript[userIdx:endIdx]
 80→		responses := extractAssistantResponses(slice)
 81→		files := extractModifiedFiles(slice)
 82→
 83→		pairs = append(pairs, PromptResponsePair{
 84→			Prompt:    prompt,
 85→			Responses: responses,
 86→			Files:     files,
 87→		})
 88→	}
 89→
 90→	return pairs
 91→}
