 93→// extractUserPromptAt extracts the user prompt at the given index.
 94→// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
 95→func extractUserPromptAt(lines []transcriptLine, idx int) string {
 96→	if idx >= len(lines) || lines[idx].Type != transcriptTypeUser {
 97→		return ""
 98→	}
 99→
100→	return transcript.ExtractUserContent(lines[idx].Message)
101→}
