103→// extractAssistantResponses collects all assistant text blocks from the given transcript slice.
104→// A single prompt can trigger multiple assistant responses interspersed with tool calls.
105→func extractAssistantResponses(transcript []transcriptLine) []string {
106→	var texts []string
107→	for _, line := range transcript {
108→		if line.Type == transcriptTypeAssistant {
