369→
370→	for i, line := range transcript {
371→		if line.UUID == uuid {
372→			return transcript[:i+1]
373→		}
374→	}
375→
376→	// UUID not found, return full transcript
377→	return transcript
378→}
379→
380→// writeTranscript writes transcript lines to a file in JSONL format.
381→func writeTranscript(path string, transcript []transcriptLine) error {
382→	file, err := os.Create(path) //nolint:gosec // Writing to controlled git metadata path
383→	if err != nil {
384→		return fmt.Errorf("failed to create file: %w", err)
385→	}
386→	defer func() { _ = file.Close() }()
387→
388→	for _, line := range transcript {
389→		data, err := json.Marshal(line)
390→		if err != nil {
391→			return fmt.Errorf("failed to marshal line: %w", err)
392→		}
393→		if _, err := file.Write(data); err != nil {
394→			return fmt.Errorf("failed to write line: %w", err)
395→		}
396→		if _, err := file.WriteString("\n"); err != nil {
397→			return fmt.Errorf("failed to write newline: %w", err)
398→		}
399→	}
400→
401→	return nil
402→}
403→
404→// TranscriptPosition contains the position information for a transcript file.
405→type TranscriptPosition struct {
406→	LastUUID  string // Last non-empty UUID (from user/assistant messages)
407→	LineCount int    // Total number of lines
408→}
409→
410→// GetTranscriptPosition reads a transcript file and returns the last UUID and line count.
411→// Returns empty position if file doesn't exist or is empty.
412→// Only considers UUIDs from actual messages (user/assistant), not summary rows which use leafUuid.
413→func GetTranscriptPosition(path string) (TranscriptPosition, error) {
414→	if path == "" {
415→		return TranscriptPosition{}, nil
416→	}
417→
418→	file, err := os.Open(path) //nolint:gosec // Reading from controlled transcript path
419→	if err != nil {
420→		if os.IsNotExist(err) {
421→			return TranscriptPosition{}, nil
422→		}
423→		return TranscriptPosition{}, fmt.Errorf("failed to open transcript: %w", err)
424→	}
425→	defer func() { _ = file.Close() }()
426→
427→	var pos TranscriptPosition
428→	reader := bufio.NewReader(file)
429→
430→	for {
431→		lineBytes, err := reader.ReadBytes('\n')
432→		if err != nil && err != io.EOF {
433→			return TranscriptPosition{}, fmt.Errorf("failed to read transcript: %w", err)
434→		}
435→
436→		if len(lineBytes) == 0 {
437→			if err == io.EOF {
438→				break
439→			}
440→			continue
441→		}
442→
443→		pos.LineCount++
444→
445→		// Parse line to extract UUID (only from user/assistant messages, not summaries)
446→		var line transcriptLine
447→		if err := json.Unmarshal(lineBytes, &line); err == nil {
448→			if line.UUID != "" {
449→				pos.LastUUID = line.UUID
450→			}
451→		}
452→
453→		if err == io.EOF {
454→			break
455→		}
456→	}
457→
458→	return pos, nil
459→}
