 14→// TranscriptLine is an alias to the shared transcript.Line type.
 15→type TranscriptLine = transcript.Line
 16→
 17→// Type aliases for internal use.
 18→type (
 19→	userMessage      = transcript.UserMessage
 20→	assistantMessage = transcript.AssistantMessage
 21→	toolInput        = transcript.ToolInput
 22→)
