 24→// SerializeTranscript converts transcript lines back to JSONL bytes
 25→func SerializeTranscript(lines []TranscriptLine) ([]byte, error) {
 26→	var buf bytes.Buffer
 27→	for _, line := range lines {
 28→		data, err := json.Marshal(line)
 29→		if err != nil {
 30→			return nil, fmt.Errorf("failed to marshal line: %w", err)
 31→		}
 32→		buf.Write(data)
 33→		buf.WriteByte('\n')
 34→	}
 35→	return buf.Bytes(), nil
 36→}
