 38→// ExtractModifiedFiles extracts files modified by tool calls from transcript
 39→func ExtractModifiedFiles(lines []TranscriptLine) []string {
 40→	fileSet := make(map[string]bool)
 41→	var files []string
 42→
 43→	for _, line := range lines {
 44→		if line.Type != "assistant" {
 45→			continue
 46→		}
 47→
 48→		var msg assistantMessage
 49→		if err := json.Unmarshal(line.Message, &msg); err != nil {
 50→			continue
 51→		}
 52→
 53→		for _, block := range msg.Content {
 54→			if block.Type != "tool_use" {
 55→				continue
 56→			}
 57→
 58→			// Check if it's a file modification tool
 59→			isModifyTool := false
 60→			for _, name := range FileModificationTools {
 61→				if block.Name == name {
 62→					isModifyTool = true
 63→					break
 64→				}
 65→			}
 66→
 67→			if !isModifyTool {
 68→				continue
 69→			}
 70→
 71→			var input toolInput
 72→			if err := json.Unmarshal(block.Input, &input); err != nil {
 73→				continue
 74→			}
 75→
 76→			file := input.FilePath
 77→			if file == "" {
 78→				file = input.NotebookPath
 79→			}
 80→
 81→			if file != "" && !fileSet[file] {
 82→				fileSet[file] = true
 83→				files = append(files, file)
 84→			}
 85→		}
 86→	}
 87→
 88→	return files
 89→}
