 91→// ExtractLastUserPrompt extracts the last user message from transcript
 92→func ExtractLastUserPrompt(lines []TranscriptLine) string {
 93→	for i := len(lines) - 1; i >= 0; i-- {
 94→		if lines[i].Type != "user" { //nolint:goconst // already present in codebase
 95→			continue
 96→		}
 97→
 98→		var msg userMessage
 99→		if err := json.Unmarshal(lines[i].Message, &msg); err != nil {
100→			continue
101→		}
102→
103→		// Handle string content
104→		if str, ok := msg.Content.(string); ok {
105→			return str
106→		}
107→
108→		// Handle array content (text blocks)
109→		if arr, ok := msg.Content.([]interface{}); ok {
110→			var texts []string
111→			for _, item := range arr {
112→				if m, ok := item.(map[string]interface{}); ok {
113→					if m["type"] == "text" {
114→						if text, ok := m["text"].(string); ok {
115→							texts = append(texts, text)
116→						}
117→					}
118→				}
119→			}
120→			if len(texts) > 0 {
121→				return strings.Join(texts, "\n\n")
122→			}
123→		}
124→	}
125→	return ""
126→}
