128→// TruncateAtUUID returns transcript lines up to and including the line with given UUID
129→func TruncateAtUUID(lines []TranscriptLine, uuid string) []TranscriptLine {
130→	if uuid == "" {
131→		return lines
132→	}
133→
134→	for i, line := range lines {
135→		if line.UUID == uuid {
136→			return lines[:i+1]
137→		}
138→	}
139→
140→	// UUID not found, return full transcript
141→	return lines
142→}
