237→// ExtractSpawnedAgentIDs extracts agent IDs from Task tool results in a transcript.
238→// When a Task tool completes, the tool_result contains "agentId: <id>" in its content.
239→// Returns a map of agentID -> toolUseID for all spawned agents.
240→func ExtractSpawnedAgentIDs(transcript []TranscriptLine) map[string]string {
241→	agentIDs := make(map[string]string)
242→
243→	for _, line := range transcript {
244→		if line.Type != "user" {
245→			continue
246→		}
247→
248→		// Parse as array of content blocks (tool results)
249→		var contentBlocks []struct {
250→			Type      string          `json:"type"`
251→			ToolUseID string          `json:"tool_use_id"`
252→			Content   json.RawMessage `json:"content"`
253→		}
254→
255→		var msg struct {
256→			Content json.RawMessage `json:"content"`
257→		}
258→		if err := json.Unmarshal(line.Message, &msg); err != nil {
259→			continue
260→		}
261→
262→		if err := json.Unmarshal(msg.Content, &contentBlocks); err != nil {
263→			continue
264→		}
265→
266→		for _, block := range contentBlocks {
267→			if block.Type != "tool_result" {
268→				continue
269→			}
270→
271→			// Content can be a string or array of text blocks
272→			var textContent string
273→
274→			// Try as array of text blocks first
275→			var textBlocks []struct {
276→				Type string `json:"type"`
277→				Text string `json:"text"`
278→			}
279→			if err := json.Unmarshal(block.Content, &textBlocks); err == nil {
280→				var textContentSb361 strings.Builder
281→				for _, tb := range textBlocks {
282→					if tb.Type == "text" {
283→						textContentSb361.WriteString(tb.Text + "\n")
284→					}
285→				}
286→				textContent += textContentSb361.String()
287→			} else {
288→				// Try as plain string
289→				var str string
290→				if err := json.Unmarshal(block.Content, &str); err == nil {
291→					textContent = str
292→				}
293→			}
294→
295→			// Look for agentId in the text
296→			if agentID := extractAgentIDFromText(textContent); agentID != "" {
297→				agentIDs[agentID] = block.ToolUseID
298→			}
299→		}
300→	}
301→
302→	return agentIDs
303→}
304→
305→// extractAgentIDFromText extracts an agent ID from text containing "agentId: <id>".
306→func extractAgentIDFromText(text string) string {
307→	const prefix = "agentId: "
308→	idx := strings.Index(text, prefix)
309→	if idx == -1 {
310→		return ""
311→	}
312→
313→	// Extract the ID (alphanumeric characters after the prefix)
314→	start := idx + len(prefix)
315→	end := start
316→	for end < len(text) && (text[end] >= 'a' && text[end] <= 'z' ||
317→		text[end] >= 'A' && text[end] <= 'Z' ||
318→		text[end] >= '0' && text[end] <= '9') {
319→		end++
320→	}
321→
322→	if end > start {
323→		return text[start:end]
324→	}
325→	return ""
326→}
327→
328→// CalculateTotalTokenUsage calculates token usage for a turn, including subagents.
329→// It parses the main transcript from startLine, extracts spawned agent IDs,
330→// and calculates their token usage from transcripts in subagentsDir.
331→func CalculateTotalTokenUsage(transcriptPath string, startLine int, subagentsDir string) (*agent.TokenUsage, error) {
332→	if transcriptPath == "" {
333→		return &agent.TokenUsage{}, nil
334→	}
335→
336→	// Parse transcript ONCE
337→	parsed, _, err := transcript.ParseFromFileAtLine(transcriptPath, startLine)
338→	if err != nil {
339→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
340→	}
341→
342→	// Calculate token usage from parsed transcript
343→	mainUsage := CalculateTokenUsage(parsed)
344→
345→	// Extract spawned agent IDs from the same parsed transcript
346→	agentIDs := ExtractSpawnedAgentIDs(parsed)
347→
348→	// Calculate subagent token usage
349→	if len(agentIDs) > 0 {
350→		subagentUsage := &agent.TokenUsage{}
351→		for agentID := range agentIDs {
352→			agentPath := filepath.Join(subagentsDir, fmt.Sprintf("agent-%s.jsonl", agentID))
353→			agentUsage, err := CalculateTokenUsageFromFile(agentPath, 0)
354→			if err != nil {
355→				// Agent transcript may not exist yet or may have been cleaned up
356→				continue
357→			}
358→			subagentUsage.InputTokens += agentUsage.InputTokens
359→			subagentUsage.CacheCreationTokens += agentUsage.CacheCreationTokens
360→			subagentUsage.CacheReadTokens += agentUsage.CacheReadTokens
361→			subagentUsage.OutputTokens += agentUsage.OutputTokens
362→			subagentUsage.APICallCount += agentUsage.APICallCount
363→		}
364→		if subagentUsage.APICallCount > 0 {
365→			mainUsage.SubagentTokens = subagentUsage
366→		}
367→	}
368→
369→	return mainUsage, nil
370→}
371→
372→// ExtractAllModifiedFiles extracts files modified by both the main agent and
373→// any subagents spawned via the Task tool. It parses the main transcript from
374→// startLine, collects modified files from the main agent, then reads each
375→// subagent's transcript from subagentsDir to collect their modified files too.
376→// The result is a deduplicated list of all modified file paths.
377→func ExtractAllModifiedFiles(transcriptPath string, startLine int, subagentsDir string) ([]string, error) {
378→	if transcriptPath == "" {
379→		return nil, nil
380→	}
381→
382→	// Parse main transcript once
383→	parsed, _, err := transcript.ParseFromFileAtLine(transcriptPath, startLine)
384→	if err != nil {
385→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
386→	}
387→
388→	// Collect modified files from main agent
389→	fileSet := make(map[string]bool)
390→	var files []string
391→	for _, f := range ExtractModifiedFiles(parsed) {
392→		if !fileSet[f] {
393→			fileSet[f] = true
394→			files = append(files, f)
395→		}
396→	}
397→
398→	// Find spawned subagents and collect their modified files
399→	agentIDs := ExtractSpawnedAgentIDs(parsed)
400→	for agentID := range agentIDs {
401→		agentPath := filepath.Join(subagentsDir, fmt.Sprintf("agent-%s.jsonl", agentID))
402→		agentLines, _, agentErr := transcript.ParseFromFileAtLine(agentPath, 0)
403→		if agentErr != nil {
404→			// Subagent transcript may not exist yet or may have been cleaned up
405→			continue
406→		}
407→		for _, f := range ExtractModifiedFiles(agentLines) {
408→			if !fileSet[f] {
409→				fileSet[f] = true
410→				files = append(files, f)
411→			}
412→		}
413→	}
414→
415→	return files, nil
416→}
