 50→// DetectPresence checks if Claude Code is configured in the repository.
 51→func (c *ClaudeCodeAgent) DetectPresence() (bool, error) {
 52→	// Get repo root to check for .claude directory
 53→	// This is needed because the CLI may be run from a subdirectory
 54→	repoRoot, err := paths.RepoRoot()
 55→	if err != nil {
 56→		// Not in a git repo, fall back to CWD-relative check
 57→		repoRoot = "."
 58→	}
 59→
 60→	// Check for .claude directory
 61→	claudeDir := filepath.Join(repoRoot, ".claude")
 62→	if _, err := os.Stat(claudeDir); err == nil {
 63→		return true, nil
 64→	}
 65→	// Check for .claude/settings.json
 66→	settingsFile := filepath.Join(repoRoot, ".claude", "settings.json")
 67→	if _, err := os.Stat(settingsFile); err == nil {
 68→		return true, nil
 69→	}
 70→	return false, nil
