167→func printTranscriptChanges(w io.Writer, transcriptPath, currentSession, repoRoot string) int {
168→	fmt.Fprintf(w, "\nParsing transcript: %s\n", transcriptPath)
169→
170→	var modifiedFromTranscript, newFiles, deletedFiles []string
171→
172→	// Parse transcript
173→	parsed, _, parseErr := transcript.ParseFromFileAtLine(transcriptPath, 0)
174→	if parseErr != nil {
175→		fmt.Fprintf(w, "  Error parsing transcript: %v\n", parseErr)
176→	} else {
177→		modifiedFromTranscript = extractModifiedFiles(parsed)
178→		fmt.Fprintf(w, "  Found %d modified files in transcript\n", len(modifiedFromTranscript))
179→	}
180→	// Compute new and deleted files (single git status call)
181→	// Load preState only if we have an active session (needed for new file detection)
182→	var preState *PrePromptState
183→	if currentSession != "" {
184→		var loadErr error
185→		preState, loadErr = LoadPrePromptState(currentSession)
186→		if loadErr != nil {
187→			fmt.Fprintf(w, "  Error loading pre-prompt state: %v\n", loadErr)
188→		}
189→	}
190→	// Always call DetectFileChanges - deleted files don't depend on preState
191→	fileChanges, err := DetectFileChanges(preState.PreUntrackedFiles())
192→	if err != nil {
193→		fmt.Fprintf(w, "  Error computing file changes: %v\n", err)
194→	}
195→	if fileChanges != nil {
196→		newFiles = fileChanges.New
197→		deletedFiles = fileChanges.Deleted
198→	}
199→
200→	// Filter and normalize paths
201→	modifiedFromTranscript = FilterAndNormalizePaths(modifiedFromTranscript, repoRoot)
202→	newFiles = FilterAndNormalizePaths(newFiles, repoRoot)
203→	deletedFiles = FilterAndNormalizePaths(deletedFiles, repoRoot)
204→
205→	// Print files
206→	printFileList(w, "Modified (from transcript)", "M", modifiedFromTranscript)
207→	printFileList(w, "New files (created during session)", "+", newFiles)
208→	printFileList(w, "Deleted files", "D", deletedFiles)
209→
210→	totalChanges := len(modifiedFromTranscript) + len(newFiles) + len(deletedFiles)
211→	if totalChanges == 0 {
212→		fmt.Fprintln(w, "\nNo changes detected from transcript")
213→	}
214→
215→	return totalChanges
216→}
