282→// getFileChanges returns the current file changes from git status.
283→// Returns (modifiedFiles, untrackedFiles, deletedFiles, stagedFiles, error)
284→func getFileChanges() ([]string, []string, []string, []string, error) {
285→	repo, err := openRepository()
286→	if err != nil {
287→		return nil, nil, nil, nil, err
288→	}
289→
290→	worktree, err := repo.Worktree()
291→	if err != nil {
292→		return nil, nil, nil, nil, fmt.Errorf("getting worktree: %w", err)
293→	}
294→
295→	status, err := worktree.Status()
296→	if err != nil {
297→		return nil, nil, nil, nil, fmt.Errorf("getting status: %w", err)
298→	}
299→
300→	var modifiedFiles, untrackedFiles, deletedFiles, stagedFiles []string
301→
302→	for file, st := range status {
303→		// Skip .entire directory
304→		if paths.IsInfrastructurePath(file) {
305→			continue
306→		}
307→
308→		// Check staging area first
309→		switch st.Staging {
310→		case git.Added, git.Modified:
311→			stagedFiles = append(stagedFiles, file)
312→			continue
313→		case git.Deleted:
314→			deletedFiles = append(deletedFiles, file)
315→			continue
316→		case git.Unmodified, git.Renamed, git.Copied, git.UpdatedButUnmerged, git.Untracked:
317→			// Fall through to check worktree status
318→		}
319→
320→		// Check worktree status
321→		switch st.Worktree {
322→		case git.Modified:
323→			modifiedFiles = append(modifiedFiles, file)
324→		case git.Untracked:
325→			untrackedFiles = append(untrackedFiles, file)
326→		case git.Deleted:
327→			deletedFiles = append(deletedFiles, file)
328→		case git.Unmodified, git.Added, git.Renamed, git.Copied, git.UpdatedButUnmerged:
329→			// No action needed
330→		}
331→	}
332→
333→	// Sort for consistent output
334→	sort.Strings(modifiedFiles)
335→	sort.Strings(untrackedFiles)
336→	sort.Strings(deletedFiles)
337→	sort.Strings(stagedFiles)
338→
