342→// findTranscriptForSession attempts to find the transcript file for a session.
343→// Returns the path if found, empty string if not found, or error on failure.
344→func findTranscriptForSession(sessionID string) (string, error) {
345→	// Try to get agent type from session state
346→	sessionState, err := strategy.LoadSessionState(sessionID)
347→	if err != nil {
348→		return "", fmt.Errorf("failed to load session state: %w", err)
349→	}
350→
351→	var ag agent.Agent
352→	if sessionState != nil && sessionState.AgentType != "" {
353→		ag, err = agent.GetByAgentType(sessionState.AgentType)
354→		if err != nil {
355→			return "", fmt.Errorf("failed to get agent for type %q: %w", sessionState.AgentType, err)
356→		}
357→	} else {
358→		return "", fmt.Errorf("failed to get agent from sessionID: %s", sessionID)
359→	}
360→
361→	// Resolve transcript path (checks session state's transcript_path first,
362→	// falls back to agent's GetSessionDir + ResolveSessionFile)
363→	transcriptPath, err := resolveTranscriptPath(sessionID, ag)
364→	if err != nil {
365→		return "", fmt.Errorf("failed to resolve transcript path: %w", err)
366→	}
367→
368→	// Check if it exists
369→	if _, err := os.Stat(transcriptPath); err != nil {
370→		if os.IsNotExist(err) {
371→			return "", nil // Not found, but not an error
372→		}
373→		return "", fmt.Errorf("failed to stat transcript: %w", err)
374→	}
375→
376→	return transcriptPath, nil
377→}
